use std::convert::Infallible;

// Define a type alias for our observables
type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

// Create a helper function to make a NAND gate
fn nand(name: String, a: Type, b: Type) -> Type {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |(a, b)| print!("nand {name} ({a}, {b})"))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!(" = {v}"))
        .box_it_clone()
}

// Implement the flip-flop logic using a different approach to avoid borrowing issues
fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Create behavior subjects for internal state
    let q1_subject = Local::behavior_subject::<bool, Infallible>(false);
    let q2_subject = Local::behavior_subject::<bool, Infallible>(false);

    // Clone the subjects for use in closures
    let q1_subject_clone = q1_subject.clone();
    let q2_subject_clone = q2_subject.clone();

    // Create the NAND gates
    let q1 = nand("s".to_string(), s, q1_subject.box_it_clone());
    let q2 = nand("r".to_string(), r, q2_subject.box_it_clone());

    // Subscribe to outputs to feed back into inputs
    // Use observe_on to defer the subscription to avoid borrowing conflicts
    q1.clone().observe_on(Scheduler::new()).subscribe(move |value| {
        q2_subject_clone.next(value);
    });

    q2.clone().observe_on(Scheduler::new()).subscribe(move |value| {
        q1_subject_clone.next(value);
    });

    // Return the outputs as observables
    (q1.box_it_clone(), q2.box_it_clone())
}

fn main() {
    // Create initial inputs
    let s = Local::behavior_subject::<bool, Infallible>(true);
    let r = Local::behavior_subject::<bool, Infallible>(true);

    // Create the flip-flop
    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    // Subscribe to the outputs
    q1.combine_latest(q2, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("({q1:?}, {q2:?})"));

    // Test the flip-flop
    println!("Initial state:");
    s.next(false); // (s: false, r: true) -> (q1: true, q2: false)

    println!("After s=false:");
    s.next(true); // (s: true, r: true) -> (q1: true, q2: false)

    println!("After s=true:");
    r.next(false); // (s: true, r: false) -> (q1: false, q2: true)

    println!("After r=false:");
    r.next(true); // (s: true, r: true) -> (q1: false, q2: true)

    println!("After r=true:");
}"
}

