  "main.rs": "use std::fs::OpenOptions;
use std::sync::Arc;
use tracing::{info, warn, error};
use tracing_subscriber::{fmt, layer::SubscriberExt, registry::Registry, reload, filter};

#[tokio::main]
async fn main() {
    // Create file writer
    let file = OpenOptions::new()
        .append(true)
        .create(true)
        .open("logfile.log")
        .unwrap();

    // Create the reloadable layer for console logging
    let console_layer = fmt::layer()
        .compact()
        .with_ansi(true)
        .with_filter(filter::LevelFilter::INFO);

    let (console_layer, console_reload) = reload::Layer::new(console_layer);

    // Create the file layer
    let file_layer = fmt::layer()
        .with_ansi(false)
        .with_writer(file)
        .with_filter(filter::LevelFilter::INFO);

    // Build the subscriber
    let subscriber = Registry::default()
        .with(console_layer)
        .with(file_layer);

    // Set global default
    tracing::subscriber::set_global_default(subscriber).expect("Failed to set subscriber");

    // Test logs
    info!("This is an info message");
    warn!("This is a warning message");
    error!("This is an error message");

    // Change console log level to ERROR after 2 seconds
    tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;

    println!("Changing console log level to ERROR...");
    console_reload.modify(|layer| {
        *layer.filter_mut() = filter::LevelFilter::ERROR;
    }).expect("Failed to modify console filter");

    // Test logs again
    info!("This info message should not appear in console");
    error!("This error message should appear in console");

    // Keep the program running to see the effect
    tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
}"
}

