}

impl CommandCompleter {
    fn new() -> Self {
        CommandCompleter {
            commands: vec![
                "ls".to_string(),
                "cd".to_string(),
                "pwd".to_string(),
                "echo".to_string(),
                "exit".to_string(),
                "help".to_string(),
            ],
        }
    }
