// using expectrl with tokio for async handling.

use expectrl::{Session, Spawn, Pty, Timeout};
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tokio::sync::{Mutex, mpsc};
use tokio::time::{sleep, Duration};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AgentMessage {
    pub content: String,
}

pub struct Agent {
    session: Arc<Mutex<Session<Pty>>>,
    sender: mpsc::UnboundedSender<String>,
}

impl Agent {
    pub async fn new() -> Result<Self, Box<dyn std::error::Error>> {
        // Create a PTY session
        let pty = Pty::new()?;
        let mut session = Session::spawn(pty)?;

        // Start reading in background
        let session_clone = session.clone();
        let (tx, mut rx) = mpsc::unbounded_channel::<String>();
        let session_arc = Arc::new(Mutex::new(session_clone));

        let reader_session = session_arc.clone();
        tokio::spawn(async move {
            let mut buf = [0u8; 1024];
            loop {
                // Non-blocking read using expectrl's timeout feature
                match reader_session.lock().await.read(&mut buf, Timeout::from_millis(100)) {
                    Ok(0) => {
                        println!("[agent] process terminated");
                        break;
                    }
                    Ok(n) => {
                        let output = String::from_utf8_lossy(&buf[..n]).to_string();
                        println!('[agent] output: {}', output);
                    }
                    Err(e) => {
                        eprintln!("[agent] read error: {}", e);
                        sleep(Duration::from_millis(10)).await;
                    }
                }
            }
        });

        // Handle incoming messages
        let writer_session = session_arc.clone();
        tokio::spawn(async move {
            while let Some(msg) = rx.recv().await {
                let mut session = writer_session.lock().await;
                if let Err(e) = session.send(&msg).await {
                    eprintln!("[agent] send error: {}", e);
                }
            }
        });

        Ok(Agent {
            session: session_arc,
            sender: tx,
        })
    }

    pub async fn send(&self, data: &str) {
        if let Err(e) = self.sender.send(data.to_string()) {
            eprintln!("[agent] failed to send: {}", e);
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting concurrent PTY agent...");

    let agent = Agent::new().await?;

    // Simulate sending some commands
    agent.send("echo Hello World\n").await;
    agent.send("ls -la\n").await;

    // Wait a bit to see output
    sleep(Duration::from_secs(2)).await;

    println!("Done.");
    Ok(())
}"
}

