  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::sync::mpsc::Sender;

pub struct Context(i32);

// Define a trait for async functions that can be called once
pub trait AsyncFnOnce<A> {
    type Output;
    type CallOnceFuture: Future<Output = Self::Output> + Send;
    fn call_once(self, arg: A) -> Self::CallOnceFuture;
}

// Implement AsyncFnOnce for async closures
impl<F, Fut, A, R> AsyncFnOnce<A> for F
where
    F: FnOnce(A) -> Fut,
    Fut: Future<Output = R> + Send,
{
    type Output = R;
    type CallOnceFuture = Fut;

    fn call_once(self, arg: A) -> Self::CallOnceFuture {
        self(arg)
    }
}

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>> + Send>,
    },
}

pub fn with_context_async<F>(work_sender: &Sender<InnerAsyncEvent>, block: F)
where
    F: for<'a> AsyncFnOnce<&'a mut Context> + Send + 'static,
{
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx: &mut Context| {
            let fut = block.call_once(ctx);
            Box::pin(fut)
        }),
    });
}

#[tokio::main]
async fn main() {
    let (sender, receiver) = std::sync::mpsc::channel::<InnerAsyncEvent>();

    // Send an async task using our helper function
    with_context_async(&sender, |ctx: &mut Context| async move {
        ctx.0 += 1;
        println!("Context value: {}", ctx.0);
    });

    // Receive and execute the task
    let event = receiver.recv().unwrap();

    tokio::spawn(async {
        let mut ctx = Context(0);
        let fut = match event {
            InnerAsyncEvent::DoWithContext { block } => block(&mut ctx),
        };
        fut.await;
    }).await.unwrap();
}
