{
  "Cargo.toml": " [package]
name = "broadcast-shutdown-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1.0", features = ["full"] }
futures = "0.3"
",
  "main.rs": "use tokio::sync::broadcast::{self, Receiver, Sender};
use tokio_stream::{self as stream, Stream};
use futures::stream::{self, StreamExt};
use std::sync::Arc;

#[derive(Debug, Clone)]
pub struct Event {
    pub message: String,
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(20);
    (EventSender { tx: tx.clone() }, EventStreamFactory { tx })
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }

    // Method to check if sender is still active
    pub fn is_closed(&self) -> bool {
        self.tx.is_closed()
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, broadcast::error::RecvError>> + Send + '_ {
        stream::unfold(self.tx.subscribe(), |mut rx| async {
            match rx.recv().await {
                Ok(event) => Some((Ok(event), rx)),
                Err(broadcast::error::RecvError::Lagged(_)) => {
                    // Handle lagged errors if needed
                    None
                }
                Err(broadcast::error::RecvError::Closed) => None,
            }
        })
    }
}

#[tokio::main]
async fn main() {
    println!("Starting server...");

    // Create the channel
    let (sender, factory) = events_channel();

    // Spawn a task to send some events
    let sender_clone = sender.clone();
    let send_task = tokio::spawn(async move {
        for i in 0..10 {
            let event = Event {
                message: format!("Event {}", i),
            };
            sender_clone.send(event);

            // Small delay between events
            tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;

            // Check if we should stop sending
            if sender_clone.is_closed() {
                break;
            }
        }

        println!("Finished sending events");
    });

    // Create a stream for events
    let mut event_stream = factory.all_events();

    // Process events
    let process_task = tokio::spawn(async move {
        while let Some(event_result) = event_stream.next().await {
            match event_result {
                Ok(event) => {
                    println!("Received: {}", event.message);
                }
                Err(e) => {
                    println!("Stream ended: {:?}", e);
                    break;
                }
            }
        }

        println!("Event processing completed");
    });

    // Wait for a bit to see events
    tokio::time::sleep(tokio::time::Duration::from_secs(3)).await;

    // Shutdown by dropping the sender
    drop(sender);

    // Wait for tasks to complete
    let _ = tokio::try_join!(send_task, process_task);

    println!("Server shutdown complete");
}"
}
